// Verify Shopify webhook HMAC signature
const crypto = require('crypto');

const body = $input.first().json.body;
const hmacHeader = $input.first().json.headers['x-shopify-hmac-sha256'];
const shopifySecret = $env.SHOPIFY_WEBHOOK_SECRET;

if (!shopifySecret) {
  throw new Error('SHOPIFY_WEBHOOK_SECRET environment variable not set');
}

// Calculate expected HMAC
const hash = crypto
  .createHmac('sha256', shopifySecret)
  .update(body, 'utf8')
  .digest('base64');

const isValid = hash === hmacHeader;

if (!isValid) {
  throw new Error('Invalid Shopify webhook signature');
}

// Parse the JSON body
const order = JSON.parse(body);

return [{
  json: {
    ...order,
    webhook_verified: true,
    verified_at: new Date().toISOString()
  }
}];

// Extract order data from Shopify webhook payload
const shopifyOrder = $input.first().json;

// Extract customer info
const customer = shopifyOrder.customer || {};
const customerName = `${customer.first_name || ''} ${customer.last_name || ''}`.trim() || 'Unknown';
const customerEmail = shopifyOrder.email || customer.email || null;

// Extract line items
const items = (shopifyOrder.line_items || []).map(item => ({
  sku: item.sku || `SHOPIFY-${item.product_id}-${item.variant_id}`,
  quantity: item.quantity || 1,
  vendor: item.vendor || 'Unknown',
  product_id: item.product_id,
  variant_id: item.variant_id,
  title: item.title,
  price: item.price
}));

// Filter out items without SKUs (digital products, gift cards, etc.)
const validItems = items.filter(item => item.sku && !item.sku.startsWith('SHOPIFY-'));

if (validItems.length === 0) {
  throw new Error('No valid SKUs found in Shopify order');
}

// Create standardized order object (same format as MarketTime)
const order = {
  order_id: `SHOPIFY-${shopifyOrder.order_number || shopifyOrder.id}`,
  source: 'shopify',
  customer_name: customerName,
  customer_email: customerEmail,
  order_date: shopifyOrder.created_at || new Date().toISOString(),
  items: validItems,
  total_items: validItems.length,
  total_quantity: validItems.reduce((sum, item) => sum + item.quantity, 0),
  shopify_order_id: shopifyOrder.id,
  shopify_order_number: shopifyOrder.order_number,
  financial_status: shopifyOrder.financial_status,
  fulfillment_status: shopifyOrder.fulfillment_status,
  parsed_at: new Date().toISOString()
};

return [{ json: order }];

// Validate extracted order data
const order = $input.first().json;
const errors = [];

// Required fields validation
if (!order.order_id) errors.push('Missing order_id');
if (!order.customer_email) errors.push('Missing customer_email');
if (!order.items || order.items.length === 0) errors.push('No items in order');

// Email validation
if (order.customer_email && !order.customer_email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) {
  errors.push('Invalid customer email format');
}

// SKU validation
for (const item of order.items || []) {
  if (!item.sku) errors.push(`Item missing SKU: ${JSON.stringify(item)}`);
  if (!item.quantity || item.quantity < 1) errors.push(`Invalid quantity for SKU ${item.sku}`);
}

// Shopify-specific validation
if (order.financial_status !== 'paid' && order.financial_status !== 'authorized') {
  errors.push(`Order not paid (status: ${order.financial_status})`);
}

if (errors.length > 0) {
  return [{
    json: {
      ...order,
      validation_failed: true,
      validation_errors: errors,
      error_message: errors.join('; ')
    }
  }];
}

return [{
  json: {
    ...order,
    validation_passed: true
  }
}];

// Handle validation errors
const failedOrder = $input.first().json;

return [{
  json: {
    error_type: 'shopify_order_validation_failed',
    order_id: failedOrder.order_id || 'UNKNOWN',
    shopify_order_id: failedOrder.shopify_order_id,
    customer_email: failedOrder.customer_email || 'UNKNOWN',
    validation_errors: failedOrder.validation_errors || [],
    financial_status: failedOrder.financial_status,
    fulfillment_status: failedOrder.fulfillment_status,
    timestamp: new Date().toISOString(),
    action_required: 'Manual review needed'
  }
}];
